/**
 * @fileoverview Heading constants.
 * @module module/Heading/constants
 */

import { defineParts } from '../shared/definePart.js';

export const CLS = Object.freeze({
    ROOT: 'heading',
});

export const DEFAULTS = Object.freeze({});

export const PART = defineParts('Heading', {
    ROOT: { class: 'heading-root', aliases: ['root', 'heading', 'h'] },
});

PART.ROOT.jit = 'text-[var(--hd-size)] fw-[var(--hd-weight)] fg-[var(--hd-text)] [font-family:var(--hd-font-stack)] [letter-spacing:var(--hd-tracking)] [line-height:var(--hd-leading)]';

/** Default size/weight per heading level */
export const LEVEL_STYLES = Object.freeze({
    h1: { size: '2.25rem',  weight: '800' },
    h2: { size: '1.75rem',  weight: '700' },
    h3: { size: '1.375rem', weight: '600' },
    h4: { size: '1.125rem', weight: '600' },
    h5: { size: '1rem',     weight: '600' },
    h6: { size: '0.875rem', weight: '600' },
});
